/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Ordem Producao"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &ProSetCod.IsEmpty() print printBlockFilterProSetCod EndIf If not &AuxGrupHie.IsEmpty() print printBlockFilterAuxGrupHie EndIf If not &ProRef.IsEmpty() print printBlockFilterProRef EndIf If not &ProCodNom.IsEmpty() print printBlockFilterProCodNom EndIf If not &ProTipDef.IsEmpty() &FilterProTipDefValueDescription = &ProTipDef.EnumerationDescription()
print printBlockFilterProTipDef EndIf If not &GrupHie.IsEmpty() print printBlockFilterGrupHie EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If not &ProGraCod.IsEmpty() print printBlockFilterProGraCod EndIf If not &ProSts.IsEmpty() &FilterProStsValueDescription = &ProSts.EnumerationDescription()
print printBlockFilterProSts EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod ProSts ProGraCod ProSetCod ProCod when &OrderedBy = 1 order EmpCod FilCod ProSts ProGraCod ProSetCod ProNom when &OrderedBy = 2 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstPrio) when &OrderedBy = 3 order EmpCod FilCod ProSts ProGraCod ProSetCod EstPrd when &OrderedBy = 4 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstPrd) when &OrderedBy = 5 order EmpCod FilCod ProSts ProGraCod ProSetCod EstQtd when &OrderedBy = 6 order EmpCod FilCod ProSts ProGraCod ProSetCod EstDias when &OrderedBy = 7 order EmpCod FilCod ProSts ProGraCod ProSetCod (EstSug) when &OrderedBy = 8 order EstABC_Ren when &OrderedBy = 9 AND &OrderedDsc = False order (EstABC_Ren) when &OrderedBy = 9 AND &OrderedDsc = True order EstABC_Qtd when &OrderedBy = 10 AND &OrderedDsc = False order (EstABC_Qtd) when &OrderedBy = 10 AND &OrderedDsc = True
using DSWWOrdemProducaoItens(&ProSetCod, &AuxGrupHie, &ProRef, &ProCodNom, &ProTipDef, &GrupHie , &FilCod, &ProGraCod, &ProSts) &gridProRef = ProRef &gridProNom = ProNom &gridEstPrd_Formatado = EstPrd_Formatado &gridEstCom_Formatado = EstCom_Formatado &gridEstQtd_Formatado = EstQtd_Formatado &gridEstVen_Formatado = EstVen_Formatado &gridEstSdo_Formatado = EstSdo_Formatado &gridEstMinDia = EstMinDia &gridEstMin_Formatado = EstMin_Formatado &gridEstSug_Formatado = EstSug_Formatado
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWOrdemProducaoItensGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWOrdemProducaoItensGridState")) Else &GridState.FromXml(&Session.Get(!"WWOrdemProducaoItensGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PROSETCOD" &ProSetCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"AUXGRUPHIE" &AuxGrupHie.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROREF" &ProRef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROCODNOM" &ProCodNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROTIPDEF" &ProTipDef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"GRUPHIE" &GrupHie.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROGRACOD" &ProGraCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTS" &ProSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
